        function obj = loadSLfeather_fromRESORT(obj,dirname)
            % icme\loadSLfeather_fromRESORT loads SL from a RESORT file
            % generated with AD old scripts, this funciton only exists for
            % sanity checks when reproducing old figures
            % output
            %    obj (icme) IC recording with filled SL field
            % input  
            %   obj (ICME) IC recording to be analysed
            %   dirname (str) path to the _RESORT file that was created
            %   with the old AD analysis scripts

            
            save_name = strcat(obj.SeriesID,"_Resort.mat");

            if isfile(fullfile(gen_dir_name(dirname),save_name))
                ResortFile = load(fullfile(gen_dir_name(dirname),save_name));
                SpikList_all=ResortFile.Spik_list;
                all_electrode_ids=0:1:31;
                spik_lists_all={};
                all_electrode_names={};
                for elec_i=1:length(all_electrode_ids)
                    all_electrode_names{end+1}=sprintf('elec%i',all_electrode_ids(elec_i));
                    cur_spik_list=SpikList_all(find(SpikList_all(:,4)==all_electrode_ids(elec_i)),:);
                    spik_lists_all.(all_electrode_names{end})=cur_spik_list;
                end
                SL.spik_list_all=spik_lists_all;
                SL.all_electrode_names=all_electrode_names; % constantly needed for further analysis
                SL.all_electrodes=[0:1:length(all_electrode_names)-1]';
                SL.analysis_parameters=['loaded from AD resort file']; 
                obj.SL=SL;
                    
            else
                fprintf('no AD style resort file found for %s \n',obj.SeriesID)
            end
        
        end


        %
        function obj = stim(obj)
            % populates the stim field of the icme. It requires that the raw
            % data are already loaded.
            obj(1).Stim(1).exp_type=obj.ExpInfo.exp_type; %MX_tones or OBISPulse etc
            obj(1).Stim(1).stimlist =obj.ExpInfo.stimlist; % descriptive table of the used stimuli
            % For creeLED10x1, check if 'stimlist' is a cell and convert it to double if needed
            if iscell(     obj(1).Stim(1).stimlist)
                % Iterate through the cell array and convert non-numeric entries to NaN
                for i = 1:numel(obj(1).Stim(1).stimlist)
                    if isempty(obj(1).Stim(1).stimlist{i}) || ~isnumeric(obj(1).Stim(1).stimlist{i})
                        obj(1).Stim(1).stimlist{i} = 0; % Replace empty or non-numeric cells with 0
                    end
                end
                % Now attempt to convert the cell array to a double
                obj(1).Stim(1).stimlist = cell2mat(obj(1).Stim(1).stimlist);
            end
            obj(1).Stim(1).stimheader = obj.ExpInfo.stimheader; % header of previous table
            obj(1).Stim(1).dura = obj.ExpInfo.dura; % duration of the full stimulus for each condition
            obj(1).Stim(1).n_rep= obj.ExpInfo.n_rep; % number of presentations per stimulus
        end

        function obj = setRawDataDir (obj, updateRawDataDir)
            % icme\setRawDataDir update the rawDataDirectory
            % variable type - struct
%                 obj.D= updateRawDataDir;

                if any(contains(updateRawDataDir.dir,obj.ExpID))
                    obj.D= updateRawDataDir;
                else
                    warning(sprintf('%s: the raw  data directory does not contain the expID. Operation aborted. Are you sure you know what you are doing?',obj.SeriesID))
                end
            
        end

        function bad_elecs = findBadElectrodes(obj,meanSpikeRates)
            % icme\findBadElectrodes by checking for outliers in the Spike rate
            % ( more than 3 times std from mean) for the first presented
            % stimulus which should have the intensity 0 (mW or dB)
            % input:
            %    obj icme
            %   meanSpikeRates (optional) 32xnum_stimuli double containing
            %       calculated spike rates for each electrode and stimulus
            % output:
            %   bad_elecs nx1 array of electrodes that were detected as bad
           
            % if no spike list is provided
            if nargin<2
                [meanSpikeRates,~]  = calculateSpikeRate(obj);
            end
            if strcmp(obj.ExpInfo.exp_type,'MX_tones')
                if obj.Stim.stimlist(1,4)~=0
                    fprintf('no 0 intensity stimulus for %s',string(obj.SeriesID))
                    bad_elecs=[];
                    return
                end
            elseif contains(obj.ExpInfo.exp_type,'OBIS_LS594_Pulse')
                if obj.Stim.stimlist(1,1)~=0
                    fprintf('no 0 intensity stimulus for %s',string(obj.SeriesID))
                    bad_elecs=[];
                    return
                end
            end
            hasOutliers = isoutlier(meanSpikeRates(:,1),"mean");% check if it is an outlier for first Presented stimulus
            hasOutliers=any(hasOutliers,2); % check if any electrode was outlier for any stimulus
            bad_elecs=obj.SL.all_electrodes(hasOutliers)+1;
        end


    end
end